<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
			:border-radius="20" :closeable="true" :z-index="100" @close="close" @open="open">
			<view class="popup-content">
				<view class="title">{{title}}</view>
				<view class="form-box">
					<u-form :model="form" ref="uForm" label-width="120">
						<u-form-item label="关键字" prop="keyword">
							<u-input v-model="form.keyword" placeholder="所有单号/商品名称/充值账号/卡密" />
						</u-form-item>
						<u-form-item label="日期" prop="create_time">
							<view class="date-box" @click="showDate">
								<view class="date">
									<template v-if="form.create_time.length">
										<view class="date-item">
											{{form.create_time[0]}}
										</view>
										<view class="date-item">
											{{form.create_time[1]}}
										</view>
									</template>
									<template v-else>
										<text class="c-gray">选择日期</text>
									</template>
								</view>
								<view class="icon">
									<u-icon name="calendar" />
								</view>
							</view>
						</u-form-item>
						<u-form-item :border-bottom="false">
							<view class="btn-box">
								<uni-view class="btn cancel-btn" @click="reset">重 置</uni-view>
								<uni-view class="btn buy_btn" @click="save">提 交</uni-view>
							</view>
						</u-form-item>
					</u-form>

				</view>
			</view>
		</u-popup>
		<date-selector-popup ref="date-selector-popup" @change="onDateChange" />
	</view>
</template>

<script>
	import DateSelectorPopup from '../date-selector-popup'

	export default {
		components: {
			DateSelectorPopup,
		},
		data() {
			return {
				title: '搜索订单',
				popupShow: false,

				form: {
					keyword: "",
					create_time: []
				},
				rules: {

				},
				dateShow: false,
			}
		},
		computed: {

		},
		watch: {

		},
		onReady() {

		},
		methods: {
			showEdit({
				keyword,
				createTime
			}) {
				this.form.keyword = keyword
				this.form.create_time[0] = createTime.shift()
				this.form.create_time[1] = createTime.shift()
				this.popupShow = true
			},
			open() {},
			close() {
				this.$emit('update:show', false)
			},
			save() {
				this.$refs.uForm.setRules(this.rules)
				this.$refs.uForm.validate(valid => {
					if (valid) {
						this.$emit('search', {
							...this.form
						})
						this.popupShow = false
					}
				})
			},
			onDateChange(e) {
				const {
					startDate,
					endDate
				} = e
				console.log(startDate, endDate)
				this.form.create_time = [startDate, endDate]
			},
			reset() {
				// this.$refs['uForm'].resetFields()
			},
			showDate() {
				this.$refs['date-selector-popup'].showEdit({
					create_time: [...this.form.create_time]
				})
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		padding: 40rpx;

		.title {
			text-align: center;
			padding-bottom: 20rpx;
			font-size: 30rpx;
			font-weight: bolder;
			border-bottom: 1px solid #e5e5e5;
		}

		.btn-box {
			display: flex;
			align-items: center;
			justify-content: center;
			width: 100%;
			gap: 40rpx;

			.btn {
				line-height: 52rpx;
				min-width: 160rpx;
				border-radius: 26rpx;
				border: 2rpx solid $u-border-color;
				font-size: 26rpx;
				text-align: center;
				color: #333;
				display: inline-block;
			}

			.buy_btn {
				color: #fff;
				background-image: linear-gradient(90deg, #FE8A56, #FF504B);
			}
		}

		.date-box {
			display: flex;
			align-items: center;
			width: 100%;
			gap: 20rpx;

			.date {
				flex: 1;
			}

			.icon {
				font-size: 36rpx;
				width: 40rpx;
			}
		}
	}
</style>