<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
			:border-radius="20" :closeable="true" :z-index="100" @close="close" @open="open">
			<view class="popup-content">
				<view class="title">{{title}}</view>
				<view class="selector">
					<DateSelector :mode="4" @onChange="onDateSelectorChange" @onSubmit="onDateSelectorSubmit"
						:defaultStartDate="defaultStartDate" :defaultEndDate="defaultEndDate" />
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	import DateSelector from '@/components/dengrq-datetime-picker/dateSelector/index.vue'
	export default {
		components: {
			DateSelector
		},
		props: {
			mode: {
				type: [Number, String],
				default: 4
			},
			minDate: {
				type: String,
				default: ''
			},
			maxDate: {
				type: String,
				default: ''
			},
		},
		data() {
			return {
				title: '日期选择器',
				popupShow: false,

				defaultStartDate: '',
				defaultEndDate: ''
			}
		},
		watch: {
			show(nv) {
				this.popupShow = nv
			},
		},
		methods: {
			showEdit({
				create_time
			}) {
				this.defaultStartDate = create_time[0] || ''
				this.defaultEndDate = create_time[1] || ''
				this.popupShow = true
			},
			open() {},
			close() {

			},
			onDateSelectorChange({
				startDate,
				endDate
			}) {
				// console.log('onDateSelectorChange', startDate, endDate)
			},
			onDateSelectorSubmit({
				startDate,
				endDate
			}) {
				// console.log('onDateSelectorSubmit', startDate, endDate)
				this.popupShow = false
				this.$emit('change', {
					startDate,
					endDate
				})
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		padding: 40rpx;

		.title {
			text-align: center;
			padding-bottom: 20rpx;
			font-size: 30rpx;
			font-weight: bolder;
			border-bottom: 1px solid #e5e5e5;
		}

		.selector {
			margin-top: 20rpx;
		}
	}
</style>