<template>
	<view class="wrap">
		<copy-param-popup ref="copy-param-popup" />
		<u-navbar :custom-back="backpage">
			<view class="search-wrap">
				<!-- <u-search v-model="keyword" disabled placeholder="所有单号/商品名称/充值账号/卡密" height="56" :show-action="false"
					@search="search" @custom="search">
				</u-search> -->
				<view class="search" @click="showSearch">
					<u-icon name="search" size="30" color="#666" />
					<text class="placeholder">所有单号/商品名称/充值账号/卡密</text>
				</view>
			</view>
			<template #right>
				<view class="navbar-right">
					<u-image :src="$util.img('/template/h5/diy/static/img/tabbar/user.png')" width="34" height="34"
						@click="$util.on('/pages/ucenter/index')" />
					<view class="right-item" @click="onCopyParam">
						<u-icon name="order" size="36" color="#333" />
					</view>
				</view>
			</template>
		</u-navbar>
		<view class="u-tabs-box">
			<u-tabs-swiper :active-color="'#f29100'" ref="tabs" :list="orderList" :current="current" @change="change"
				:is-scroll="false" swiperWidth="750"></u-tabs-swiper>
		</view>

		<scroll-view scroll-y style="height: 100%;width: 100%;" @scrolltolower="reachBottom">
			<view class="page-box">
				<view class="order" v-for="(order, orderindex) in list" :key="order.id">
					<view class="top">
						<view class="check-box">
							<u-checkbox v-model="order.checked" active-color="#FF504B"></u-checkbox>
						</view>
						<view class="left" @click="paste(order.ordersn)">
							<view class="tag" v-if="order.type">{{order._type_text}}</view>
							<view class="store">{{ order.ordersn }}</view>
							<u-icon name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon>
						</view>
						<view class="right" :style="{
									color:statusColor[order.status].color
								}">{{ order.status_text }}</view>
					</view>
					<view class="item" @click="$util.on('/pages/order/info?id='+order.id)">
						<view class="left">
							<image :src="$util.img(order.goods_img)" mode="aspectFill"></image>
						</view>
						<view class="content">
							<view class="title u-line-2">{{ order.goods_name }}</view>
							<view class="type" v-if="order.goods_sku_name">{{ order.goods_sku_name }}</view>
							<view class="type">{{ order.goods_type_text }}</view>
							<view class="delivery-time" v-if="order.recharge_info && order.recharge_info.length > 0"
								style="color: #9b9fa8;">
								<view class="" v-for="(item,index) in order.recharge_info" :key="index">
									<template v-if="item.t == 'images'">

									</template>
									<template v-else-if="item.t == 'checkbox'">
										{{item.n}} {{item.v.join(',')}}
									</template>
									<template v-else>
										{{item.n}} {{item.v}}
									</template>
								</view>
							</view>
							<view class="progress" v-if="order.goods_type == 2 && orderProgressNum(order)">
								<text class="label">下单进度</text><u-line-progress active-color="#2979ff"
									:percent="orderProgressNum(order)"></u-line-progress>
							</view>
							<view class="delivery-time">下单时间
								{{ $util.timeFormat(order.create_time,'yyyy-mm-dd hh:MM:ss') }}
							</view>
							<view class="delivery-time" v-if="order.finish_time">完成时间
								{{ $util.timeFormat(order.finish_time,'yyyy-mm-dd hh:MM:ss') }}
							</view>
						</view>
						<view class="right">
							<view class="price">
								￥{{ priceInt(order.price) | showPrice }}
								<text class="decimal">.{{ priceDecimal(order.price) | showPrice }}</text>
							</view>
							<view class="number">x{{ order.quantity }}</view>
							<view v-if="order.has_back_money && order.has_back_money>0"
								style="color: #ff5500;font-size:26rpx;">
								退:{{ order.has_back_money }}</view>

						</view>
					</view>
					<view class="total">
						共{{ order.quantity }}件商品 合计:
						<text class="total-price">

							￥{{ priceInt(order.total_price) | showPrice }}
							<text class="decimal">.{{ priceDecimal(order.total_price) | showPrice}}</text>
						</text>
					</view>
					<view class="bottom">

						<view class="btn c-red" v-if="order.goods_type == 2" @click="paste('',2,order)">复制信息
						</view>
						<view class="btn c-red"
							v-if="order.goods_type == 1 && order.card_list && order.card_list.length"
							@click="paste('',1,order)">复制卡密
						</view>
						<view class="btn bg-red c-gray" style="color: #fff;" @click="handleCancel(order)"
							v-if="order.can_back == 1">申请撤单</view>
						<view class="btn c-gray" v-if="order.status == 1 || order.status == 2 || order.status == 3"
							@click="$util.on(`/pages/buyer/addcomplain?ordersn=${order.ordersn}`)">
							申请售后</view>

						<view v-if="order.status == 0" class="btn buy_btn"
							@click="$util.on('/pages/goods/buy?ordersn='+order.ordersn)">立即支付
						</view>
						<view class="btn buy_btn" @click="$util.on('/pages/goods/detail?id='+order.goods_id)">再次购买
						</view>
					</view>
				</view>


				<u-loadmore :status="loadStatus" icon-type="circle" v-if="list.length >0 && loaded" />
			</view>
			<u-empty v-if="loaded &&  list.length == 0" mode="order"></u-empty>

		</scroll-view>
		<order-search-popup ref="order-search-popup" @search="onSearch" />
	</view>
</template>

<script>
	import CopyParamPopup from './components/copy-param-popup'
	import OrderSearchPopup from './components/order-search-popup'
	import _ from 'lodash'

	export default {
		components: {
			CopyParamPopup,
			OrderSearchPopup
		},
		data() {
			return {
				keyword: '',
				createTime: [],
				sys: this.$util.sys(),
				limit: 10,
				orderList: [{
						name: '全部',
						loadStatus: 'loadmore',
						page: 1,
						status: '',
						count: 0,
						list: []
					},
					{
						name: '待付款',
						loadStatus: 'loadmore',
						page: 1,
						status: 0,
						count: 0,
						list: []
					},
					{
						name: '待处理',
						loadStatus: 'loadmore',
						page: 1,
						status: 1,
						count: 0,
						list: []
					},
					{
						name: '处理中',
						loadStatus: 'loadmore',
						page: 1,
						status: 2,
						count: 0,
						list: []
					},
					{
						name: '已完成',
						loadStatus: 'loadmore',
						page: 1,
						status: 3,
						count: 0,
						list: []
					},

					{
						name: '已退款',
						loadStatus: 'loadmore',
						page: 1,
						status: 5,
						count: 0,
						list: []
					},
				],

				statusColor: {
					'-1': {
						color: '#999'
					},
					'0': {
						color: '#999'
					},
					'1': {
						color: '#f7b24b'
					},
					'2': {
						color: '#ff8507'
					},
					'3': {
						color: '#90dd90'
					},
					'4': {
						color: '#ff5500'
					},
					'5': {
						color: '#ff5500'
					}
				},


				loadStatus: 'loadmore',
				page: 1,
				status: '',
				count: 0,
				list: [],
				current: 0,
				swiperCurrent: 0,
				loaded: false,
				dx: 0,
			};
		},
		onLoad(e) {
			if (e.status) {
				this.swiperCurrent = e.status
				this.current = e.status
				this.status = this.orderList[e.status].status
			}
			// this.getCreateTime();
			this.loadData(this.swiperCurrent)
		},
		computed: {
			// 价格小数
			priceDecimal() {
				return val => {
					if (val !== parseInt(val)) return val.split('.')[1];
					else return '00';
				};
			},
			// 价格整数
			priceInt() {
				return val => {
					if (val !== parseInt(val)) return val.split('.')[0];
					else return val;
				};
			},
			selectRows() {
				return this.list.filter((item) => item.checked)
			}
		},
		methods: {
			getCreateTime() {
				// const start = new Date()
				// const end = new Date()
				// start.setHours(0)
				// start.setMinutes(0)
				// start.setSeconds(0)
				// start.setMilliseconds(0)
				// end.setHours(23)
				// end.setMinutes(59)
				// end.setSeconds(59)
				// end.setMilliseconds(0)

				// return [this.$kss.formatDate(start), this.$kss.formatDate(end)]


				let default_search_time = uni.getStorageSync('default_search_time')
				let startTime = new Date()
				startTime.setHours(0, 0, 0)
				// startTime.setMonth(startTime.getMonth() - 1)
				startTime.setDate(startTime.getDate() - (default_search_time || 0))
				let endTime = new Date()
				//endTime.setDate(endTime.getDate() + 1)
				endTime.setHours(23, 59, 59)

				this.createTime = [this.$kss.formatDate(startTime), this.$kss.formatDate(endTime)]
				

			},
			backpage() {
				this.$util.back()
			},
			paste(val, type, order) {
				if (!val) {
					val = '';
				}

				//充值信息
				if (type == 1) {
					for (let i = 0; i < order.card_list.length; i++) {

						if (order.card_list[i].card_no && order.card_list[i].card_no != '') {
							val += order.card_list[i].card_no + ' ' + order.card_list[i]
								.card_password + "\r\n"
						} else {
							val += order.card_list[i].card_password + "\r\n"
						}
					}

					// #ifdef H5
					window._agl && window._agl.push(['track', ['success', {
						t: 1
					}]])
					// #endif

				} else if (type == 2 && order.recharge_info) {

					for (let i = 0; i < order.recharge_info.length; i++) {
						val += order.recharge_info[i].v + "\r\n"
					}
				}
				if (val) {
					val = val.replace(/<br>/ig, '\r\n');
					val = val.replace(/(^\s*)|(\s*$)/g, "");
					val = val.replace(/&amp;/ig, '&');
				}

				uni.setClipboardData({
					data: val + '',
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});

					}
				})
			},
			handleCancel: _.throttle(async function(order) {
				const {
					ordersn
				} = order
				await this.$u.api.applyCancel({
					ordersn
				})
				this.$util.msg('申请撤单成功')
			}, 500),
			reachBottom() {


				setTimeout(() => {
					this.loadData(this.current);
				}, 200);

			},
			search() {
				this.orderList[0].list = []
				this.orderList[0].page = 1
				this.current = 0
				this.swiperCurrent = 0
				this.page = 1
				this.list = []
				this.loadData(0)

			},
			onSearch(e) {
				const {
					keyword,
					create_time
				} = e
				this.keyword = keyword
				this.createTime = create_time

				this.search()
			},
			// 页面数据
			async loadData(idx) {

				uni.showLoading({
					mask: true,
					title: '加载中...',

				})
				await this.$u.api.orderList({
						status: this.status,
						keyword: this.keyword,
						create_time: this.createTime,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {
						if (res.list.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.list)

							} else {
								this.list = res.list

							}

							if (res.list.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}

					}).catch(res => {})
				this.loaded = true
				uni.hideLoading()
				//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页

				// console.log(item	);
			},
			// 总价
			totalPrice(item) {
				let price = 0;
				item.map(val => {
					price += parseFloat(val.price);
				});
				return price.toFixed(2);
			},
			// 总件数
			totalNum(item) {
				let num = 0;
				item.map(val => {
					num += val.number;
				});
				return num;
			},
			// tab栏切换
			change(index) {
				this.swiperCurrent = index;
				this.current = index;
				this.list = []
				this.page = 1;
				this.status = this.orderList[index].status;
				this.loadData(index);
			},
			transition({
				detail: {
					dx
				}
			}) {

				this.$refs.tabs.setDx(dx);
			},
			animationfinish({
				detail: {
					current
				}
			}) {

				this.$refs.tabs.setFinishCurrent(current);
				this.swiperCurrent = current;
				this.current = current;
				if (!this.orderList[current].loaded) {
					this.loadData(current)
				}
			},
			orderProgressNum({
				current_progress,
				target_progress
			}) {
				if (target_progress)
					return ((current_progress / target_progress) * 100)
				else return 0
			},
			onCopyRechargeInfo(order) {
				let str = ''
				for (let i = 0; i < order.recharge_info.length; i++) {
					str += order.recharge_info[i].v + "\r\n"
				}
				if (str) {
					str = str.replace(/<br>/ig, '\r\n');
					str = str.replace(/(^\s*)|(\s*$)/g, "");
					str = str.replace(/&amp;/ig, '&');
				}
				uni.setClipboardData({
					data: str,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			showSearch() {
				this.$refs['order-search-popup'].showEdit({
					keyword: this.keyword,
					createTime: [...this.createTime]
				})
			},
			async onCopyParam() {
				let list = []
				if (this.selectRows.length) {
					list = _.cloneDeep(this.selectRows)
				} else {
					uni.showLoading({
						mask: true,
						title: '加载中...',
					})
					
					if(this.createTime.length == 0){
						this.getCreateTime()
					}
					list = await this.$u.api.orderList({
						status: this.status,
						keyword: this.keyword,
						page: this.page,
						limit: this.limit,
						is_copy: 1,
						is_copy_field: 'recharge_info,card_list,recharge_hints,ordersn,external_orderno',
						create_time: this.createTime,
					})
					uni.hideLoading()
				}

				let export_data = list.map((item) => {
					if (item.recharge_info && Array.isArray(item.recharge_info)) {
						let arr = []
						let tmp = ``
						let tmp2 = []
						item.recharge_info.map((item2) => {
							if (item2.t == 'images' || item2.t == 'checkbox') {
								if (Array.isArray(item2.v)) {
									// tmp2.push(`${item2.n}:${item2.v.join(',')}`)
									tmp2.push(`${item2.v.join(',')}`)
								} else {
									// tmp2.push(`${item2.n}:${item2.v}`)
									tmp2.push(`${item2.v}`)
								}
							} else {
								// tmp2.push(`${item2.n}:${item2.v}`)
								tmp2.push(`${item2.v}`)
							}
						})
						arr.push(`${tmp}${tmp2.join(',')}`)

						item.recharge_info = arr.filter(Boolean).join('\r\n')
					}

					//卡密处理
					if (item.card_list && item.card_list.length) {
						let strArr = item.card_list.map((item1) => {
							if (item1.card_no) {
								return `${item1.card_no} ${item1.card_password}`
							} else {
								return `${item1.card_password}`
							}
						})
						item.card_list = strArr.join('\r\n')
					}

					//订单耗时处理
					item.take_up_time =
						item.pay_time > 0 && item.pay_time != item.finish_time ?
						this.timeSub(item.pay_time * 1000, item.finish_time * 1000) :
						item.pay_time > 0 ?
						'0秒' :
						'-'

					return item
				})
				let columns = [{
						key: 'ordersn',
						title: '订单号'
					},
					{
						key: 'external_orderno',
						title: '三方单号'
					},
					{
						key: 'recharge_info',
						title: '下单参数'
					},
					{
						key: 'card_list',
						title: '卡券信息'
					},
					{
						key: 'recharge_hints',
						title: '充值返回'
					}
				]

				let defaultCheckColumns = columns.map((item) => item.key)
				this.$refs['copy-param-popup'].showEdit({
					columns,
					defaultCheckColumns,
					data: export_data
				})
			}
		}
	};
</script>


<style scoped>
	page {
		height: 100%;
		background-color: #f2f2f2;
	}
</style>
<style lang="scss" scoped scoped>
	.order {
		width: 710rpx;
		background-color: #ffffff;
		margin: 20rpx auto;
		border-radius: 20rpx;
		box-sizing: border-box;
		padding: 20rpx;
		font-size: 28rpx;

		.top {
			display: flex;
			justify-content: space-between;
			align-items: center;

			.left {
				display: flex;
				align-items: center;
				flex: 1;

				.tag {
					border: 1px solid #FF504B;
					color: #FF504B;
					padding: 2rpx 4rpx;
					font-size: 20rpx;
					border-radius: 6rpx;
				}

				.store {
					margin: 0 10rpx;
					font-size: 24rpx;
					font-weight: bold;
				}
			}

			.right {
				color: $u-type-warning-dark;
			}
		}

		.item {
			display: flex;
			margin: 20rpx 0 0;
			justify-content: space-between;

			.left {
				margin-right: 20rpx;

				image {
					width: 160rpx;
					height: 160rpx;
					border-radius: 10rpx;
				}
			}

			.content {
				overflow: hidden;
				flex: 1;

				.title {
					font-size: 28rpx;
					line-height: 50rpx;
				}

				.type {
					// margin: 10rpx 0;
					font-size: 24rpx;
					color: $u-tips-color;
				}

				.delivery-time {
					// color: #e5d001;
					font-size: 24rpx;
				}

				.progress {
					display: flex;
					gap: 10rpx;
					align-items: center;

					.label {
						font-size: 24rpx;
						white-space: nowrap;
					}
				}
			}

			.right {
				margin-left: 10rpx;
				padding-top: 8rpx;
				text-align: right;

				.decimal {
					font-size: 24rpx;
					margin-top: 4rpx;
				}

				.number {
					color: $u-tips-color;
					font-size: 24rpx;
				}
			}
		}

		.total {
			// margin-top: 20rpx;
			text-align: right;
			font-size: 24rpx;

			.total-price {
				font-size: 32rpx;
			}

			.decimal {
				font-size: 24rpx;
				margin-top: 4rpx;
			}
		}

		.bottom {
			display: flex;
			margin-top: 12rpx;
			// padding: 0 10rpx;
			row-gap: 20rpx;
			justify-content: flex-end;
			align-items: center;
			flex-wrap: wrap;

			.btn {
				line-height: 52rpx;
				min-width: 160rpx;
				border-radius: 26rpx;
				border: 2rpx solid $u-border-color;
				font-size: 26rpx;
				text-align: center;
			}

			.buy_btn {

				color: #fff;
				background-image: linear-gradient(90deg, #FE8A56, #FF504B);
			}

			.evaluate {
				color: $u-type-warning-dark;
				border-color: $u-type-warning-dark;
			}
		}
	}

	.centre {
		text-align: center;
		margin: 200rpx auto;
		font-size: 32rpx;

		image {
			width: 164rpx;
			height: 164rpx;
			border-radius: 50%;
			margin-bottom: 20rpx;
		}

		.tips {
			font-size: 24rpx;
			color: #999999;
			margin-top: 20rpx;
		}

		.btn {
			margin: 80rpx auto;
			width: 200rpx;
			border-radius: 32rpx;
			line-height: 64rpx;
			color: #ffffff;
			font-size: 26rpx;
			background: linear-gradient(270deg, rgba(249, 116, 90, 1) 0%, rgba(255, 158, 1, 1) 100%);
		}
	}

	.wrap {
		display: flex;
		flex-direction: column;
		height: calc(100vh - var(--window-top));
		width: 100%;
	}

	.swiper-box {
		flex: 1;
