<template>
	<u-popup v-model="popupShow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
		:border-radius="20" width="600rpx" :closeable="true" :z-index="100" @close="close" @open="open">
		<view class="popup-content">
			<view class="title">{{title}}</view>
			<view class="form-box">
				<u-form :model="form" ref="uForm" label-width="120" label-position="top">
					<u-form-item label="选择列" prop="checkedColumns">
						<u-checkbox-group active-color="#FF504B" size="30" @change="checkboxGroupChange">
							<u-checkbox label-size="26" @change="checkboxChange" v-model="column.checked"
								v-for="(column, idx) in columns" :key="idx"
								:name="column.key">{{column.title}}</u-checkbox>
						</u-checkbox-group>
					</u-form-item>
					<u-form-item :border-bottom="false">
						<view class="btn-box">
							<uni-view class="btn cancel-btn" @click="popupShow=false">取 消</uni-view>
							<uni-view class="btn buy_btn" @click="save">确 定</uni-view>
						</view>
					</u-form-item>
				</u-form>

			</view>
		</view>
	</u-popup>
</template>

<script>
	export default {
		components: {

		},
		data() {
			return {
				title: '复制参数',
				popupShow: false,
				columns: [],
				data: [],
				form: {
					checkedColumns: [],
				},
				rules: {
					checkedColumns: [{
						validator: (rule, value, callback) => {
							return value.length > 0
						},
						message: '至少选择一个列',
						trigger: ['change', 'blur'],
					}]
				},
				dateShow: false,
			}
		},
		computed: {

		},
		onReady() {

		},
		methods: {
			showEdit({
				columns,
				defaultCheckColumns,
				data
			}) {
				this.form.checkedColumns = [...defaultCheckColumns]
				this.columns = columns.map((item) => {
					return {
						name: item.key,
						title: item.title,
						checked: defaultCheckColumns.includes(item.key),
						disabled: false
					}
				})
				this.data = [...data]
				this.popupShow = true
			},
			open() {},
			close() {

			},
			checkboxGroupChange(e) {
				this.form.checkedColumns = this.columns.filter(item => item.checked).map(item => item.name)
			},
			checkboxChange() {

			},
			save() {
				this.$refs.uForm.setRules(this.rules)
				this.$refs.uForm.validate(valid => {
					if (valid) {
						if (!this.data.length) {
							uni.showToast({
								title: '数据为空，无法复制',
								mask: false,
								duration: 1500,
								icon: 'none'
							})
							return
						}
						// 复制文本
						let text = ''
						//将符合checkedColumns中id的data中的值拼接起来复制
						this.data.forEach((item) => {
							let temp = ''
							this.form.checkedColumns.forEach((item2) => {
								temp += (temp ? ' ' : '') + item[item2]
							})
							text += temp + '\n'
						})
						uni.setClipboardData({
							data: text,
							success: function() {
								uni.showToast({
									title: '复制成功',
									mask: false,
									duration: 1500,
									icon: 'none'
								})
							}
						})
						setTimeout(() => {
							this.$emit('fetch-data')
							this.popupShow = false
						}, 1000)
					}
				})
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		padding: 40rpx;

		.title {
			text-align: center;
			padding-bottom: 10rpx;
			font-size: 30rpx;
			font-weight: bolder;
			border-bottom: 1px solid #e5e5e5;
		}

		.btn-box {
			display: flex;
			align-items: center;
			justify-content: center;
			width: 100%;
			gap: 40rpx;

			.btn {
				line-height: 52rpx;
				min-width: 160rpx;
				border-radius: 26rpx;
				border: 2rpx solid $u-border-color;
				font-size: 26rpx;
				text-align: center;
				color: #333;
				display: inline-block;
			}

			.buy_btn {
				color: #fff;
				background-image: linear-gradient(90deg, #FE8A56, #FF504B);
			}
		}
	}
</style>